+        cancelled: Rc<RefCell<bool>>,
+    }
+
+    impl CancelAfterFirstOverflowFreeStore {
+        fn new(inner: Rc<RefCell<MemPageStore>>) -> Self {
+            Self {
+                inner,
+                cancelled: Rc::new(RefCell::new(false)),
+            }
+        }
